def ex(en, ja, focus, obj=None, jaFocus=None):
    d={'en':en,'ja':ja,'focus':focus}
    if obj: d['object']=obj
    if jaFocus: d['jaFocus']=jaFocus
    return d

def meaning(i, mid, title, pattern, struct, image, point, examples, daily):
    return {'id':mid,'title':f'{i} {title}','pattern':pattern,'transitivity':'他動詞・自動詞','structure':struct,'image':image,'point':point,'examples':examples,'dailyExamples':daily}

def phrase(ph, ja, pattern, examples, daily):
    return {'phrase':ph,'ja':ja,'image':f'{ph} は仕事で「{ja}」場面に使いやすい表現です。','pattern':pattern,'examples':examples,'dailyExamples':daily}

def make_phrases(items):
    out=[]
    for ph,ja in items:
        out.append(phrase(ph,ja,ph.upper()+' + ...',[
            ex(f'I will {ph} this today.',f'今日これを{ja}します。',ph,'this',ja),
            ex(f'We need to {ph} it before the meeting.',f'会議前にそれを{ja}する必要があります。',ph,'it',ja),
            ex(f'Please {ph} the details with the team.',f'詳細をチームと{ja}してください。',ph,'the details',ja)
        ],[
            ex(f'I often {ph} this at home.',f'家でよくこれを{ja}します。',ph,'this',ja),
            ex(f'It helps to {ph} in daily life.',f'日常生活で{ja}できると役立ちます。',ph,None,ja)
        ]))
    return out

def verb_obj(id, rank, word, ipa, kana, core, detail, visual_from, meanings, collocs, phrasals):
    return {
      'id':id,'rank':rank,'word':word,'ipa':ipa,'kana':kana,'syllable':id,
      'transitivity':'他動詞・自動詞','importance':'★★★★☆ 重要','core':core,'coreDetail':detail,
      'coreVisual':{'from':visual_from,'to':'仕事の流れ','label':'コアイメージ'},
      'meanings':meanings,'collocations':make_phrases(collocs),'phrasalVerbs':make_phrases(phrasals)
    }

