 meaning(5,'restart','再開する','START + again / over','S + V','一度止まったものを再び始める。','start again / start over はやり直しで便利です。',[ex('Let us start again from the main issue.','主要な問題からもう一度始めましょう。','start',None,'始め'),ex('We started over after the system error.','システムエラー後にやり直しました。','started over',None,'やり直しました'),ex('Can we start the discussion again?','議論を再開できますか？','start','the discussion','再開')],[ex('I want to start over this year.','今年やり直したいです。','start over',None,'やり直したい'),ex('She started again after a break.','彼女は休憩後に再開しました。','started',None,'再開しました')]),
 meaning(6,'start-work','仕事を始める','START work / START at 会社','S + V + O','勤務や仕事を始める。','start work は仕事開始、start at は勤務先開始。',[ex('I start work at nine.','私は9時に仕事を始めます。','start','work','仕事を始め'),ex('She started at our company last month.','彼女は先月当社で働き始めました。','started',None,'働き始めました'),ex('He will start his new role next week.','彼は来週新しい役職を始めます。','start','his new role','始めます')],[ex('I started a new job in April.','4月に新しい仕事を始めました。','started','a new job','始めました'),ex('My day starts with coffee.','私の1日はコーヒーで始まります。','starts',None,'始まります')]),
 meaning(7,'start-from','〜から始める','START from + 起点','S + V + 前置詞句','起点を示して始める。','説明や確認の出だしに便利です。',[ex('Let us start from the budget.','予算から始めましょう。','start',None,'始めましょう'),ex('We should start from the customer needs.','顧客ニーズから始めるべきです。','start',None,'始める'),ex('The process starts from this form.','手続きはこのフォームから始まります。','starts',None,'始まります')],[ex('I started from zero.','ゼロから始めました。','started',None,'始めました'),ex('The trip starts from Tokyo.','旅行は東京から始まります。','starts',None,'始まります')]),
