objs={'start':start,'show':show,'open':openv,'close':close,'let':let}

def find_obj(text,idv):
    pat=f'\n  {{\n    "id": "{idv}"'
    m=re.search(re.escape(pat), text)
    if not m: return None
    start=m.start()+1
    depth=0; in_str=False; esc=False
    for i,ch in enumerate(text[start:], start):
        if in_str:
            if esc: esc=False
            elif ch=='\\': esc=True
            elif ch=='"': in_str=False
        else:
            if ch=='"': in_str=True
            elif ch=='{': depth+=1
            elif ch=='}':
                depth-=1
                if depth==0:
                    end=i+1
                    if end < len(text) and text[end]==',': end+=1
                    return start,end
    return None

for idv,obj in objs.items():
    loc=find_obj(s,idv)
    txt='  '+json.dumps(obj,ensure_ascii=False,indent=4).replace('\n','\n  ')+','
    if loc:
        s=s[:loc[0]]+txt+s[loc[1]:]
    else:
        # insert before build if possible, otherwise before array end
        loc2=find_obj(s,'build')
        if loc2:
            s=s[:loc2[0]]+txt+'\n'+s[loc2[0]:]
        else:
            s=s.replace('\n];\n\nexport const testItems', '\n'+txt+'\n];\n\nexport const testItems')

p.write_text(s)
print('v34 verbs updated')
